var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"대, 대장님! 헬기가 파괴됐습니다!","JPN":"た、隊長！　ヘリが壊されました！","ENG":"C-Captain! Our chopper has been destroyed!","TWN":"隊、隊長！直升機被破壞了！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"이젠 도망칠 수도 없어요! 으아아, 우린 끝장이야!!","JPN":"もう逃げることもできません！　うわああ、俺たちはもう終わりだ！","ENG":"We can't even run now! Waaah, we're going to die!","TWN":"這下跑也跑不了了！哇啊啊啊，我們完蛋了！！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"이디스! 괜찮아요?","JPN":"イーディス！　大丈夫？","ENG":"Edith! Are you okay?","TWN":"伊蒂絲！妳沒事吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"흠냐...... 쿠울......","JPN":"……すやすや……","ENG":"*Smacks her lips* ... Zzz...","TWN":"呼嚕……呼嚕……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"으아, 이런 소란 중에도 잠에서 깨지 않다니 대단한 아가씨네.","JPN":"うわぁ、こんな時にも起きないなんてすごいね～","ENG":"Geez, how can she stay asleep in the middle of this madness? She's incredible.","TWN":"哇，這麼吵竟然還能睡，真是個了不起的女孩。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"그래도 다친 곳이 없어서 다행이야!","JPN":"でも、怪我がなくてよかった！","ENG":"At least she's not hurt.","TWN":"不管怎樣，沒受傷太好了！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"습격해온 침식체와 용병들이 갑자기 자기들끼리 싸우는 덕분에 쉽게 이겼어.","JPN":"襲ってきた侵食体と傭兵たちが、急にお互い争い始めたおかげで簡単に勝てたな。","ENG":"The C.O.s and mercenaries fought each other all of a sudden. We didn't have to do much to win.","TWN":"多虧侵蝕體和傭兵之間起了內訌，我們才沒費什麼力氣就打敗他們。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"먼지랑 연기가 심해서 잘 안 보이는데...... 대체 지금 무슨 일이 벌어지고 있는 거람?","JPN":"砂埃で前が全然見えないけど……いったい何が起きているの？","ENG":"I can't see through all this dust and smoke. What's happening right now?","TWN":"因為灰塵和煙霧太多看不清楚……但到底在發生什麼事？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"OGRE2_NPC_NULL_NULL","text":{"KOREA":"(검은 머리 여자! 다쳤나?)","JPN":"(黒髪の女！　怪我したか？)","ENG":"(Black-haired female! Are you hurts?)","TWN":"（黑髮女！受傷了嗎？）"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_09"},{"id":"L17_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"(많이 안 다쳤다! 다행이다!)","JPN":"(軽傷だ！　よかった！)","ENG":"(She's not hurts much! Good!)","TWN":"（傷勢不重！太好了！）"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_08"},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아......","JPN":"あぁ……","ENG":"Ah...","TWN":"啊……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"너희들이...... 날 도와줬구나.","JPN":"あなたたちが……助けてくれたのね。","ENG":"You helped me.","TWN":"是你們……救了我。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"하하......","JPN":"はは……","ENG":"Hah hah...","TWN":"哈哈……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"난 침식체라고 이용하려고만 했는데, 왠지 미안해지네.","JPN":"私は侵食体を利用することしか考えてなかったのに、何か悪いことしちゃったみたい。","ENG":"Now, I feel guilty for trying to use you because you're C.O.s.","TWN":"我只想著要利用你們這些侵蝕體，真是抱歉。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"확실히 우리가 운명으로 이어져있긴 한 모양이야.","JPN":"私たちって、やっぱり運命で繋がってるみたいね？","ENG":"We really must be connected by destiny.","TWN":"看來我們的命運確實是連在一起的。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"하지만......","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아무래도 너희와 계속 함께 할 수는 없을 거 같아.","JPN":"やっぱりあなたたちとは一緒にいられない。","ENG":"I don't think I can stay with you guys.","TWN":"我沒辦法跟你們在一起。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"나, 운명의 상대가 누군지 이젠 알게 됐거든.","JPN":"私、運命の相手が誰かわかった気がするの。","ENG":"I've figured out whom I want.","TWN":"因為我知道我的命運之人是誰了。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"처음 운명의 상대를 찾으려고 했을 땐 먼 곳만 보고 있었지......","JPN":"最初に運命の相手を探そうとしたときは、遠いところばかり見てた……","ENG":"At first, I was looking so far away to find my soul mate","TWN":"剛開始在尋找命運之人的時候，我還以為他離我很遠……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"정작 가장 가까운 곳에 그 운명이 있다는 걸 모르고 있었던 거야.","JPN":"すぐ近くにその運命があるって気づかずに。","ENG":"that I didn't know he was right next to me.","TWN":"但卻沒意識到他一直就在我的身邊。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"어쩌면 알고는 있었지만, 내 마음이 솔직하지 못했던 걸지도 몰라.","JPN":"もしかしたら知ってたのかもしれない。でも正直になれなかったんだと思う。","ENG":"Or maybe I knew; I just wasn't being honest with myself.","TWN":"或許我早就意識到了，只是我不夠坦率。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"10년 전의 발렌타인 때 고백을 거절당하고 자신감을 잃은 뒤로, 한 번도 그런 용기를 내본 적이 없었으니까.","JPN":"10年前のバレンタインで振られて自信を失ってから、一度も勇気を出したことがなかったから。","ENG":"I haven't had enough courage to open myself up to anyone since the rejection on Valentine's Day ten years ago.","TWN":"自從在10年前的情人節告白失敗後，我就一直沒能鼓起勇氣。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"하지만 지금이라면 확신이 생겨. 그 사람 앞에서, 용기를 내어 말할 수 있을 것 같아.","JPN":"でも今は確信を持てた。あの人の前で勇気を出して言える気がする。","ENG":"But not anymore. I want to be courageous in front of him.","TWN":"但是現在，我想我可以在那個人面前鼓起勇氣告白了。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"비록 너희를 멋대로 이용하려 한 나지만...... 이런 내 마음을 이해해줄 수 있을까?","JPN":"あなたたちを利用しようとした私だけど……こんな私の気持ち、わかってくれるかな？","ENG":"I'm sorry I tried to use you. Could you understand me?","TWN":"雖然我利用了你們……但你們能理解我的心情嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"OGRE2_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OGRE2_NPC_NULL_NULL","text":{"KOREA":"(너도 나와 같은 것을 느끼는가?)","JPN":"(お前も俺と同じことを感じているか？)","ENG":"(Are you having the same sentiment as I?)","TWN":"（你也和我有同樣的感受嗎？）"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_36"},{"id":"L40_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"(아아, 느껴지는군. 그녀는 지금 진정한 사랑을 깨달은 것이다.)","JPN":"(あぁ、感じる。彼女は今真の愛に気づいたんだ。)","ENG":"(Aaah, I am. She's found true love.)","TWN":"（啊啊，我感受到了。她領悟了真正的愛情。）"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_35"},{"id":"L41_1","type":"dialog","speaker":"OGRE2_NPC_NULL_NULL","text":{"KOREA":"(그래, 저런 진짜 사랑은 힘과 집착만으로는 손에 넣을 수 없는 것이지.)","JPN":"(そうだ。真の愛とは執着だけでは手に入らないもの。)","ENG":"(Yes, and true love can't be attained through force or unhealthy obsession.)","TWN":"（對，真正的愛情是不能靠蠻力和執著來得到的。）"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_09"},{"id":"L42_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"(우린 바람에 나부끼는 억새처럼 눈먼 본능에만 휘둘리고 있었다.)","JPN":"(俺たちは風になびくススキのように、本能に目がくらんでいた。)","ENG":"(We've been letting our instincts sway us like reeds in the wind.)","TWN":"（我們卻像隨風飄蕩的蘆葦一樣，被盲目的本能所驅使。）"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_08"},{"id":"L43_1","type":"dialog","speaker":"OGRE2_NPC_NULL_NULL","text":{"KOREA":"(어째서 그리도 어리석었는지.)","JPN":"(なんという愚かな……)","ENG":"(We've been so foolish.)","TWN":"（我們怎麼會這麼愚蠢。）"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_05"},{"id":"L44_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"(사랑하는 이를 위해, 그 사랑을 놓아주는 것 또한, 우리가 표현할 수 있는 사랑의 방식.)","JPN":"(愛する者のために、その愛を手放すこともまた、俺たちが表現できる愛し方。)","ENG":"(If we really care for her, we should let her go join her true love.)","TWN":"（為了心愛之人選擇放手，也是我們表達愛意的方式。）"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_03"},{"id":"L45_1","type":"dialog","speaker":"OGRE2_NPC_NULL_NULL","text":{"KOREA":"(이젠 나도 그녀를 응원해줄 때가 된 것 같군.)","JPN":"(俺たちも彼女を応援してあげる時が来たようだ。)","ENG":"(Agreed. It's time I watch her from behind...)","TWN":"（看來是我們幫她加油的時候了。）"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_02"},{"id":"L46_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"저기. 왜 침식체가 셰익스피어 같은 제스쳐를 섞으면서 대화를 하고 있는진 모르겠지만......","JPN":"どうして侵食体同士がシェイクスピアみたいなジェスチャーを使いながら話してるのかよくわからないけど……","ENG":"Hey, I don't know why you C.O.s are talking with Shakespearean gestures,","TWN":"那個，雖然不知道侵蝕體說話時，為什麼做出莎士比亞劇中的動作……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"일단 나머지 이야기는 여기서 벗어난 후에 하는 게 좋을 것 같아.","JPN":"とりあえず続きはここから抜け出した後にした方がよさそうね。","ENG":"but you should talk later. We need to get out of here first.","TWN":"剩下的事情還是等我們離開這裡再說吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"크읏, 이 빛은 뭐지......?","JPN":"くっ、この光は……？","ENG":"Ack, what's this light?","TWN":"啊，這道光是……？"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"꺄아악!!","JPN":"きゃああっ！？","ENG":"Kyaaaak!","TWN":"呀啊！！"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_EXPLOSION_ENERGY_BIG_08"}]`);export{e as default};